VALUES
  ('generalpolice-94737317-moex-00532', 'generalpolice-94737317', 'generalpolice-94737317-moex-111-9b499a9f', 'sub-generalpolice-94737317-02', NULL, 'single_choice', '化學反應Cl(g)＋2NO(g)→2NOCl(g)，若將Cl 之濃度加倍，反應速率為原來的2倍，當兩個反應物', '["", "", "", ""]'::jsonb, 1, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:48+00:00", "source_pdf_sha1": "46a94943e2b1", "answer_pdf_sha1": "4509f4bde46a", "source_family": "moex-gov-tw", "moex": {"exam_code": "111070", "c": "402", "s": "1606", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "普通物理學概要與普通化學概要", "year": "111", "exam_name": "111年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試", "original_question_number": 38, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "generalpolice", "civil_category": "消防警察人員"}'::jsonb, NULL),
  ('generalpolice-94737317-moex-00533', 'generalpolice-94737317', 'generalpolice-94737317-moex-111-9b499a9f', 'sub-generalpolice-94737317-02', NULL, 'single_choice', '2 的濃度均加倍，反應速率則為原來的8倍，則此反應對NO而言，其反應級數為多少？', '["1", "2", "3", "4"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:48+00:00", "source_pdf_sha1": "46a94943e2b1", "answer_pdf_sha1": "4509f4bde46a", "source_family": "moex-gov-tw", "moex": {"exam_code": "111070", "c": "402", "s": "1606", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "普通物理學概要與普通化學概要", "year": "111", "exam_name": "111年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "消防警察人員"}'::jsonb, NULL),
  ('generalpolice-94737317-moex-00534', 'generalpolice-94737317', 'generalpolice-94737317-moex-111-9b499a9f', 'sub-generalpolice-94737317-02', NULL, 'single_choice', '有關活化能及催化劑的敘述，下列何者正確？', '["催化劑的參與，不僅可以改變反應的活化能，也可改變反應熱", "催化劑對正逆反應皆有影響，不但可以改變平衡達成時間，亦可影響平衡的移動", "當反應之活化能高時，反應速率快，反應容易進行", "加熱過氧化氫水溶液為製氧方法，若在常溫下將二氧化錳加入過氧化氫水溶液，則可免去加熱步 驟。故二氧化錳為催化劑"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:48+00:00", "source_pdf_sha1": "46a94943e2b1", "answer_pdf_sha1": "4509f4bde46a", "source_family": "moex-gov-tw", "moex": {"exam_code": "111070", "c": "402", "s": "1606", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "普通物理學概要與普通化學概要", "year": "111", "exam_name": "111年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試", "original_question_number": 39, "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "消防警察人員"}'::jsonb, NULL),
  ('generalpolice-94737317-moex-00535', 'generalpolice-94737317', 'generalpolice-94737317-moex-111-9b499a9f', 'sub-generalpolice-94737317-02', NULL, 'single_choice', '下圖為二氧化碳之相圖，關於二氧化碳的敘述，下列何者正確？ Pressure(atm) Temperature (℃)', '["在室溫、70大氣壓下為液態", "在-78℃、1大氣壓下加熱，由固態轉化為液態", "在32℃、1大氣壓下加壓至80大氣壓時，會轉化為液態", "在73.7大氣壓、31.1℃時為三相共存的狀態"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:48+00:00", "source_pdf_sha1": "46a94943e2b1", "answer_pdf_sha1": "4509f4bde46a", "source_family": "moex-gov-tw", "moex": {"exam_code": "111070", "c": "402", "s": "1606", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "普通物理學概要與普通化學概要", "year": "111", "exam_name": "111年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試", "original_question_number": 40, "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "消防警察人員"}'::jsonb, NULL),
  ('generalpolice-94737317-moex-00536', 'generalpolice-94737317', 'generalpolice-94737317-moex-111-b182839b', 'sub-generalpolice-94737317-05', NULL, 'single_choice', '依憲法增修條文規定，關於立法委員之產生方式，下列敘述何者錯誤？', '["自第7屆起原住民立委共6人", "自第7屆起全國不分區及僑居國外國民代表共34人", "立法院立法委員自第7屆起113人", "各政黨提出之政黨比例代表名單中，女性不得低於二分之一"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:48+00:00", "source_pdf_sha1": "dcc9138c5f9e", "answer_pdf_sha1": "09f272857164", "source_family": "moex-gov-tw", "moex": {"exam_code": "111070", "c": "402", "s": "0605", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識(中華民國憲法概要、法學緒論)", "year": "111", "exam_name": "111年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "消防警察人員"}'::jsonb, NULL),
  ('generalpolice-94737317-moex-00537', 'generalpolice-94737317', 'generalpolice-94737317-moex-111-b182839b', 'sub-generalpolice-94737317-05', NULL, 'single_choice', '下列何者依法須事先申請集會遊行之許可？', '["大型廟會", "宗教遶境活動", "室外婚喪活動", "政黨室外跨年晚會"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:48+00:00", "source_pdf_sha1": "dcc9138c5f9e", "answer_pdf_sha1": "09f272857164", "source_family": "moex-gov-tw", "moex": {"exam_code": "111070", "c": "402", "s": "0605", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識(中華民國憲法概要、法學緒論)", "year": "111", "exam_name": "111年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "消防警察人員"}'::jsonb, NULL),
  ('generalpolice-94737317-moex-00538', 'generalpolice-94737317', 'generalpolice-94737317-moex-111-b182839b', 'sub-generalpolice-94737317-05', NULL, 'single_choice', '下列關於副總統之敘述，何者錯誤？', '["總統仍在位而僅副總統缺位時，應由總統於三個月內提名候選人，召集立法院補選", "與行政院院長職務非顯不相容，但憲法設置之本旨係兩職務應分屬不同人擔任", "副總統彈劾之事由，限於內亂或外患罪", "未享有刑事豁免權"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:48+00:00", "source_pdf_sha1": "dcc9138c5f9e", "answer_pdf_sha1": "09f272857164", "source_family": "moex-gov-tw", "moex": {"exam_code": "111070", "c": "402", "s": "0605", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識(中華民國憲法概要、法學緒論)", "year": "111", "exam_name": "111年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "消防警察人員"}'::jsonb, NULL),
  ('generalpolice-94737317-moex-00539', 'generalpolice-94737317', 'generalpolice-94737317-moex-111-b182839b', 'sub-generalpolice-94737317-05', NULL, 'single_choice', '關於立法院職權之行使，下列敘述何者錯誤？', '["除了措施性法律外，立法權原則上應受個案立法禁止原則之拘束", "有審議預算案之權，但不得為增加支出之提議", "立法院雖係最高立法機關，享有立法裁量權，但仍不得與憲法牴觸", "法律案須經立法院之議決，但未必須經三讀會通過"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:48+00:00", "source_pdf_sha1": "dcc9138c5f9e", "answer_pdf_sha1": "09f272857164", "source_family": "moex-gov-tw", "moex": {"exam_code": "111070", "c": "402", "s": "0605", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識(中華民國憲法概要、法學緒論)", "year": "111", "exam_name": "111年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "消防警察人員"}'::jsonb, NULL),
  ('generalpolice-94737317-moex-00540', 'generalpolice-94737317', 'generalpolice-94737317-moex-111-b182839b', 'sub-generalpolice-94737317-05', NULL, 'single_choice', '關於立法委員兼職之禁止，下列敘述何者錯誤？', '["憲法明文規定立法委員不得兼任官吏", "立法委員不得兼任受有俸給之文武職公務員之職務", "立法委員得兼任公營事業機構之董事、監察人及總經理", "無論常設性或臨時性機構內之公務員職務，立法委員皆不得兼任"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:48+00:00", "source_pdf_sha1": "dcc9138c5f9e", "answer_pdf_sha1": "09f272857164", "source_family": "moex-gov-tw", "moex": {"exam_code": "111070", "c": "402", "s": "0605", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識(中華民國憲法概要、法學緒論)", "year": "111", "exam_name": "111年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "消防警察人員"}'::jsonb, NULL),
  ('generalpolice-94737317-moex-00541', 'generalpolice-94737317', 'generalpolice-94737317-moex-111-b182839b', 'sub-generalpolice-94737317-05', NULL, 'single_choice', '關於憲法所規定之選舉，下列何者並非憲法第129條所要求之選舉方法？', '["公開選舉", "普通選舉", "平等選舉", "直接選舉"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:48+00:00", "source_pdf_sha1": "dcc9138c5f9e", "answer_pdf_sha1": "09f272857164", "source_family": "moex-gov-tw", "moex": {"exam_code": "111070", "c": "402", "s": "0605", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識(中華民國憲法概要、法學緒論)", "year": "111", "exam_name": "111年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "消防警察人員"}'::jsonb, NULL)
